#!/usr/bin/env python3
"""Generate src/config.h with the specified experiment configuration.

Usage:
  python helpers/gen_experiment.py --k 8 --cache-mode 0 --gpu-linear 1 --prediction 0
  python helpers/gen_experiment.py  # uses defaults
"""
import argparse
import os
import sys

TEMPLATE = """// Compile-time experiment configuration
// Auto-generated by helpers/gen_experiment.py — do not edit directly.
// Include is mandatory — infer.m will not compile without it.
#ifndef CONFIG_H
#define CONFIG_H

// Active experts per layer
#define ACTIVE_EXPERTS_PER_LAYER {k}

// Cache strategy: 0 = trust OS page cache, 1 = malloc expert cache
#define CACHE_MODE {cache_mode}

// Number of malloc cache entries (only used when CACHE_MODE=1)
#define CACHE_ENTRIES {cache_entries}

// Linear attention backend: 1 = fused GPU delta-net, 0 = CPU Accelerate BLAS
#define GPU_LINEAR {gpu_linear}

// Expert prediction: 1 = enable, 0 = disable (paper: -18%, discarded)
#define PREDICTION {prediction}

#endif // CONFIG_H
"""

DEFAULTS = {
    "k": 8,
    "cache_mode": 0,
    "cache_entries": 0,
    "gpu_linear": 1,
    "prediction": 0,
}


def generate(args):
    config_h = TEMPLATE.format(
        k=args.k,
        cache_mode=args.cache_mode,
        cache_entries=args.cache_entries,
        gpu_linear=args.gpu_linear,
        prediction=args.prediction,
    )

    repo_root = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
    out_path = os.path.join(repo_root, "src", "config.h")

    # Only write if changed (avoids unnecessary rebuilds)
    if os.path.exists(out_path):
        with open(out_path) as f:
            if f.read() == config_h:
                print(f"config.h unchanged, skipping write")
                return out_path

    with open(out_path, "w") as f:
        f.write(config_h)
    print(f"Wrote {out_path}")
    return out_path


def main():
    parser = argparse.ArgumentParser(description="Generate src/config.h")
    parser.add_argument("--k", type=int, default=DEFAULTS["k"],
                        help=f"Active experts per layer (default: {DEFAULTS['k']})")
    parser.add_argument("--cache_mode", type=int, default=DEFAULTS["cache_mode"],
                        help=f"Cache strategy (default: {DEFAULTS['cache_mode']})")
    parser.add_argument("--cache_entries", type=int, default=DEFAULTS["cache_entries"],
                        help=f"Malloc cache entries (default: {DEFAULTS['cache_entries']})")
    parser.add_argument("--gpu_linear", type=int, default=DEFAULTS["gpu_linear"],
                        help=f"GPU linear attention (default: {DEFAULTS['gpu_linear']})")
    parser.add_argument("--prediction", type=int, default=DEFAULTS["prediction"],
                        help=f"Expert prediction (default: {DEFAULTS['prediction']})")
    args = parser.parse_args()
    out = generate(args)
    print(f"Config: K={args.k}, cache_mode={args.cache_mode}, "
          f"gpu_linear={args.gpu_linear}, prediction={args.prediction}")

if __name__ == "__main__":
    main()
